// Initial Implementation
const clientId = 'your_client_id';
const redirectUri = encodeURIComponent('http://localhost:3000/callback');
const authorizationUrl = `https://auth.example.com/oauth/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=read%20write`;

function handleAuthorizationCode(code) {
  fetch(`https://auth.example.com/oauth/token`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}&client_id=${clientId}`
  })
  .then(response => response.json())
  .then(data => {
    localStorage.setItem('access_token', data.access_token);
    localStorage.setItem('refresh_token', data.refresh_token);
  });
}

// Redirect to authorization URL
window.location.href = authorizationUrl;

// Handle callback in the redirect URI
if (window.location.pathname === '/callback') {
  const urlParams = new URLSearchParams(window.location.search);
  const code = urlParams.get('code');
  if (code) {
    handleAuthorizationCode(code);
  }
}